oxy_webhelp_navlinks = {"aws_permission_categories-d27248e12148":{"topics":[{"title":"Permission model and privilege elevation for AWS","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides a least permission model for AWS cloud accounts,         granting minimal necessary permissions, starting with read-only access. You can add the             <code class=\"ph codeph\">Basic<\/code> permission category initially and elevate permissions for         recovery operations when required.<\/p>","href":"saas\/aws_perm_model_privilege_elevation.html","attributes":{"data-id":"aws_perm_model_privilege_elevation"},"menu":{"hasChildren":false},"tocID":"aws_perm_model_privilege_elevation-d27248e12161","topics":[]},{"title":"Managing granular permissions for an AWS cloud account","shortdesc":"<p class=\"shortdesc\">You can manage the permission categories for an AWS cloud account that you have         already added to <span class=\"ph\">RSC<\/span> by including or excluding permission categories, as         required.<\/p>","href":"saas\/aws_managing_granular_perms_cloud_acc.html","attributes":{"data-id":"aws_managing_granular_perms_cloud_acc"},"menu":{"hasChildren":false},"tocID":"aws_managing_granular_perms_cloud_acc-d27248e12177","topics":[]}]}};